				fp s2_sl = exp((nu - 1.0f) * d_initvalu_39 * FoRT) * pow_fp(Nao, 3.0f) * d_initvalu_37;
				fp s3_sl = (KmCai * pow_fp(Nao, 3.0f) * (1.0f + pow_fp((d_initvalu_33 / KmNai), 3.0f)) + pow_fp(KmNao, 3.0f) * d_initvalu_37 + pow_fp(KmNai, 3.0f) * Cao * (1.0f + d_initvalu_37 / KmCai) + KmCao * pow_fp(d_initvalu_33, 3.0f) + pow_fp(d_initvalu_33, 3.0f) * Cao + pow_fp(Nao, 3.0f) * d_initvalu_37) * (1.0f + ksat * exp((nu - 1.0f) * d_initvalu_39 * FoRT));
				fp I_ncx_junc = Fjunc * IbarNCX * pow_fp(Q10NCX, Qpow) * Ka_junc * (s1_junc - s2_junc) / s3_junc;
				fp I_ncx_sl = Fsl * IbarNCX * pow_fp(Q10NCX, Qpow) * Ka_sl * (s1_sl - s2_sl) / s3_sl;
